/*
 * COMP 421 Lab 1 - MonTTY Terminal Device Driver
 *
 * Mesa-style monitor for terminal device driver with 7 entry procedures.
 * All I/O synchronization and buffering happens within the monitor.
 */

#define TERMINAL_MAX_LINE 1024
#define ERROR -1

/* Structure to hold per-terminal state */
struct terminal_state {
    int initialized;
    char input_buffer[TERMINAL_MAX_LINE];  /* Line input buffer */
    int input_head;                        /* Write position in input buffer */
    int input_has_newline;                 /* Flag: does buffer contain complete line? */

    cond_id_t input_ready;                 /* Condition: line available for reading */
    cond_id_t output_ready;                /* Condition: output register free */
    int output_pending;                    /* Is output register busy? */
    char pending_output;                   /* Pending echo character */
    int has_pending_output;                /* Do we have echo output pending? */

    int writing;                           /* Is there an active WriteTerminal? */
    char *write_buf;                       /* Buffer being written */
    int write_remaining;                   /* Remaining chars to write */

    struct termstat stats;                 /* Statistics */
};

/* Global monitor state */
static int driver_initialized = 0;
static struct terminal_state terminals[NUM_TERMINALS];

/* Forward declarations of internal helper functions */
static void send_to_output(int term, char c);
static void process_input_char(int term, char c);
static void handle_write_output(int term);

/* Helper: get next output character (echo has priority) */
static char get_next_output_char(int term, int *has_char) {
    *has_char = 0;

    /* Echo has priority */
    if (terminals[term].has_pending_output) {
        *has_char = 1;
        terminals[term].has_pending_output = 0;
        return terminals[term].pending_output;
    }

    /* Then WriteTerminal output */
    if (terminals[term].write_remaining > 0) {
        *has_char = 1;
        char c = *terminals[term].write_buf++;
        terminals[term].write_remaining--;

        /* Handle output character processing: \n -> \r\n */
        if (c == '\n') {
            /* Need to send \r first, then \n on next call */
            /* For now, just mark that we need to send \r first */
            terminals[term].write_buf--;
            terminals[term].write_remaining++;
            return '\r';
        }
        return c;
    }

    return 0;
}

/*
 * Entry procedure: InitTerminalDriver
 * Must be called exactly once before any other operations.
 */
int
InitTerminalDriver(void)
{
    Declare_Monitor_Entry_Procedure();

    if (driver_initialized) {
        return ERROR;
    }

    /* Initialize all terminals */
    int i;
    for (i = 0; i < NUM_TERMINALS; i++) {
        terminals[i].initialized = 0;
        terminals[i].input_head = 0;
        terminals[i].input_has_newline = 0;
        terminals[i].output_pending = 0;
        terminals[i].has_pending_output = 0;
        terminals[i].writing = 0;
        terminals[i].write_remaining = 0;

        terminals[i].input_ready = CondCreate();
        terminals[i].output_ready = CondCreate();

        /* Mark as uninitialized */
        terminals[i].stats.tty_in = -1;
        terminals[i].stats.tty_out = -1;
        terminals[i].stats.user_in = -1;
        terminals[i].stats.user_out = -1;
    }

    driver_initialized = 1;
    return 0;
}

/*
 * Entry procedure: InitTerminal
 * Initialize a specific terminal by calling InitHardware.
 */
int
InitTerminal(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized) {
        return ERROR;
    }

    if (term < 0 || term >= NUM_TERMINALS) {
        return ERROR;
    }

    if (terminals[term].initialized) {
        return ERROR;
    }

    /* Initialize hardware */
    if (InitHardware(term) != 0) {
        return ERROR;
    }

    terminals[term].initialized = 1;
    terminals[term].stats.tty_in = 0;
    terminals[term].stats.tty_out = 0;
    terminals[term].stats.user_in = 0;
    terminals[term].stats.user_out = 0;
    terminals[term].output_pending = 0;

    return 0;
}

/*
 * Entry procedure: WriteTerminal
 * Write buflen characters to terminal, blocking until all sent.
 */
int
WriteTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    /* Validate arguments */
    if (!driver_initialized || term < 0 || term >= NUM_TERMINALS) {
        return ERROR;
    }

    if (!terminals[term].initialized) {
        return ERROR;
    }

    if (buf == NULL || buflen < 0) {
        return ERROR;
    }

    if (buflen == 0) {
        return 0;
    }

    /* Update statistics */
    terminals[term].stats.user_in += buflen;

    /* Set up write operation */
    terminals[term].write_buf = buf;
    terminals[term].write_remaining = buflen;

    /* Send characters one at a time */
    while (terminals[term].write_remaining > 0) {
        /* Wait for output register to be free */
        while (terminals[term].output_pending) {
            CondWait(terminals[term].output_ready);
        }

        /* Send next character */
        int has_char;
        char c = get_next_output_char(term, &has_char);
        if (has_char) {
            terminals[term].output_pending = 1;
            WriteDataRegister(term, c);
            terminals[term].stats.tty_out++;
        }
    }

    return buflen;
}

/*
 * Entry procedure: ReadTerminal
 * Read a line of input, blocking until \n or buffer full.
 */
int
ReadTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    /* Validate arguments */
    if (!driver_initialized || term < 0 || term >= NUM_TERMINALS) {
        return ERROR;
    }

    if (!terminals[term].initialized) {
        return ERROR;
    }

    if (buf == NULL || buflen < 0) {
        return ERROR;
    }

    if (buflen == 0) {
        return 0;
    }

    /* Wait for a complete line */
    while (!terminals[term].input_has_newline && terminals[term].input_head == 0) {
        CondWait(terminals[term].input_ready);
    }

    /* Copy data to user buffer */
    int to_copy = buflen;
    if (to_copy > terminals[term].input_head) {
        to_copy = terminals[term].input_head;
    }

    memcpy(buf, terminals[term].input_buffer, to_copy);

    /* Remove copied data from input buffer */
    int remaining = terminals[term].input_head - to_copy;
    if (remaining > 0) {
        memmove(terminals[term].input_buffer,
                terminals[term].input_buffer + to_copy,
                remaining);
    }
    terminals[term].input_head = remaining;

    /* Check if we still have a newline in buffer */
    int i;
    terminals[term].input_has_newline = 0;
    for (i = 0; i < terminals[term].input_head; i++) {
        if (terminals[term].input_buffer[i] == '\n') {
            terminals[term].input_has_newline = 1;
            break;
        }
    }

    terminals[term].stats.user_out += to_copy;

    return to_copy;
}

/*
 * Entry procedure: TerminalDriverStatistics
 * Return statistics for all terminals.
 */
int
TerminalDriverStatistics(struct termstat *stats)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || stats == NULL) {
        return ERROR;
    }

    int i;
    for (i = 0; i < NUM_TERMINALS; i++) {
        stats[i] = terminals[i].stats;
    }

    return 0;
}

/*
 * Entry procedure (bottom half): ReceiveInterrupt
 * Called when a character arrives from keyboard.
 * MUST NOT BLOCK.
 */
void
ReceiveInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || term < 0 || term >= NUM_TERMINALS) {
        return;
    }

    if (!terminals[term].initialized) {
        return;
    }

    /* Read character from hardware */
    char c = ReadDataRegister(term);
    terminals[term].stats.tty_in++;

    /* Process input character (echo and buffering) */
    process_input_char(term, c);

    /* Signal that input is ready */
    CondSignal(terminals[term].input_ready);
}

/*
 * Entry procedure (bottom half): TransmitInterrupt
 * Called when output character has been sent.
 */
void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || term < 0 || term >= NUM_TERMINALS) {
        return;
    }

    if (!terminals[term].initialized) {
        return;
    }

    /* Mark output register as free */
    terminals[term].output_pending = 0;

    /* Signal that output is ready */
    CondSignal(terminals[term].output_ready);
}

/*
 * Internal helper: Process input character
 * Handles echo and buffering. Called from ReceiveInterrupt (no blocking allowed).
 */
static void
process_input_char(int term, char c)
{
    char echo_char = c;
    int echo_it = 1;

    /* Input character processing */
    if (c == '\r' || c == '\n') {
        /* CR or LF: convert to newline, echo as CR+LF */
        if (terminals[term].input_head < TERMINAL_MAX_LINE) {
            terminals[term].input_buffer[terminals[term].input_head++] = '\n';
            terminals[term].input_has_newline = 1;
        }
        /* Echo as \r\n, but we can only send one char at a time */
        /* Queue echo output (will be sent in priority order) */
        if (!terminals[term].has_pending_output) {
            terminals[term].pending_output = '\r';
            terminals[term].has_pending_output = 1;
        }
        /* Next output will send \n after \r */
        echo_it = 0;  /* Will be echoed separately */
    }
    else if (c == '\b' || c == '\177') {
        /* Backspace/delete */
        if (terminals[term].input_head > 0) {
            terminals[term].input_head--;
            /* Echo the erase sequence: backspace, space, backspace */
            if (!terminals[term].has_pending_output) {
                terminals[term].pending_output = '\b';
                terminals[term].has_pending_output = 1;
            }
            echo_it = 0;
        } else {
            echo_it = 0;  /* Don't echo if nothing to erase */
        }
    }
    else {
        /* Regular character */
        if (terminals[term].input_head < TERMINAL_MAX_LINE) {
            terminals[term].input_buffer[terminals[term].input_head++] = c;
            echo_char = c;
        } else {
            /* Buffer full - optionally ring bell, but drop char */
            echo_it = 0;
            if (!terminals[term].has_pending_output) {
                terminals[term].pending_output = '\a';
                terminals[term].has_pending_output = 1;
            }
        }
    }

    /* Queue echo output if needed */
    if (echo_it && !terminals[term].has_pending_output) {
        terminals[term].pending_output = echo_char;
        terminals[term].has_pending_output = 1;
    }
}

